#include <bits/stdc++.h>
using namespace std;

int main() {
    ios_base::sync_with_stdio(false); cin.tie(NULL);
    int n; cin >> n;
    for (int mask = 0; mask < (1 << n); mask++) {
        bool first = true;
        for (int i = 0; i < n; i++) {
            if ((mask >> i) & 1) {
                if (!first) cout << ' ';
                cout << (i + 1);
                first = false;
            }
        }
        cout << "\n";
    }
    return 0;
}
